import React, { useState } from "react";
import { Link } from "react-router-dom";
import "./Home.css";

const heroImage = "https://images.pexels.com/photos/3185483/pexels-photo-3185483.jpeg";

const listings = [
  {
    id: 1,
    name: "Luxury Beach Villa",
    image: "https://images.pexels.com/photos/2102587/pexels-photo-2102587.jpeg",
    description: "Enjoy stunning sea views and sunsets at this beautiful villa.",
  },
  {
    id: 2,
    name: "Cozy Mountain Cabin",
    image: "https://images.pexels.com/photos/277572/pexels-photo-277572.jpeg",
    description: "A peaceful cabin nestled in the mountains with scenic views.",
  },
  {
    id: 3,
    name: "Modern City Apartment",
    image: "https://images.pexels.com/photos/271624/pexels-photo-271624.jpeg",
    description: "Stay close to the city center with top amenities and comfort.",
  },
  {
    id: 4,
    name: "Traditional Heritage Home",
    image: "https://images.pexels.com/photos/259588/pexels-photo-259588.jpeg",
    description: "Live the royal experience in a cultural heritage home.",
  },
];

export default function Home() {
  const [searchTerm, setSearchTerm] = useState("");
  const [checkIn, setCheckIn] = useState("");
  const [checkOut, setCheckOut] = useState("");
  const [guestName, setGuestName] = useState("");

  const filteredListings = listings.filter((home) =>
    home.name.toLowerCase().includes(searchTerm.toLowerCase())
  );

  return (
    <div className="home-container">
      {/* Hero Section */}
      <section
        className="hero"
        style={{ backgroundImage: `url(${heroImage})` }}
      >
        <div className="overlay">
          <h1>Find Your Perfect Stay</h1>
          <p>Book homes, villas, and experiences across the world.</p>

          {/* Search Bar */}
          <div className="search-bar">
            <input
              type="text"
              placeholder="Search destination"
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
            />
            <input
              type="date"
              value={checkIn}
              onChange={(e) => setCheckIn(e.target.value)}
            />
            <input
              type="date"
              value={checkOut}
              onChange={(e) => setCheckOut(e.target.value)}
            />
            <input
              type="text"
              placeholder="Guest name"
              value={guestName}
              onChange={(e) => setGuestName(e.target.value)}
            />
            <button>Search</button>
          </div>
        </div>
      </section>

      {/* Listings Section */}
      <section className="listings">
        <h2>Featured Stays</h2>
        <div className="cards">
          {filteredListings.length > 0 ? (
            filteredListings.map((home) => (
              <div key={home.id} className="card">
                <img src={home.image} alt={home.name} />
                <div className="card-content">
                  <h3>{home.name}</h3>
                  <p>{home.description}</p>
                  <Link to={`/booking/${home.id}`}>
                    <button>Book Now</button>
                  </Link>
                </div>
              </div>
            ))
          ) : (
            <p className="no-results">No stays found 😔</p>
          )}
        </div>
      </section>
    </div>
  );
}
